const crypto = require('crypto');
const results = [];
const items = $input.all();

for (const item of items) {
  const data = item.json;
  const content = data.content || '';
  const cleaned_content = content.replace(/\s+/g, ' ').trim();
  const content_hash = crypto.createHash('sha256').update(cleaned_content).digest('hex');

  results.push({
    json: {
      ...data,
      cleaned_content,
      content_hash
    }
  });
}
return results;

