const results = [];
const currentItems = $input.all();
const originalItems = $('Clean Notion Content').all();
for (let i = 0; i < currentItems.length; i++) {
  const current = currentItems[i].json;
  const original = originalItems[i].json;
  let category = 'Other';
  let executive_summary = {};
  try {
    const parsed = JSON.parse(current.response || current.content || '{}');
    category = parsed.category || 'Other';
    executive_summary = parsed.executive_summary || {};
  } catch (e) {
    if (current.response) category = current.response.trim();
  }
  results.push({
    json: {
      ...original,
      category,
      executive_summary: JSON.stringify(executive_summary)
    }
  });
}
return results;

